// tabletools.js — reusable hide + drag-and-drop reorder for table rows
// and dashboard sections. Drag is powered by Sortable.js (loaded ahead of
// this script) so that touch, animations, auto-scroll, and the "insertion
// indicator" semantics work out of the box across desktop and tablet.
//
// Usage in a renderer:
//   1) Each row HTML must carry:
//        data-tt-dnd="<stateKey>"     (groups draggables; same key = same scope)
//        data-tt-key="<itemKey>"      (stable identifier of this row)
//      and a hide button generated by TableTools.hideBtn(stateKey, itemKey).
//
//      Note: `draggable="true"` is no longer required — Sortable.js takes
//      over native drag. If you keep it, the attribute is harmless. Sections
//      that want a dedicated handle add <span class="drag-handle">⠿</span>
//      inside the row markup; without it, the whole row is the drag target.
//
//   2) Before rendering, transform your items array:
//        items = TableTools.applyOrder(items, stateKey, i => i.id);
//        const { visible, hidden } = TableTools.split(items, stateKey, i => i.id);
//      Render `visible` normally, then `hidden` inside a "Skryté (N)" subgroup
//      built with TableTools.hiddenSubgroupRow(stateKey, hidden.length).
//
//   3) Tell the module how to re-render on state changes:
//        TableTools.onChange(stateKey, () => renderMyTable(window.__lastData));

(function () {
    const NS = 'fs25.dash.v1.';
    const KEY_HIDDEN = k => NS + 'hidden:' + k;
    const KEY_ORDER  = k => NS + 'order:'  + k;

    // Legacy DashState key names — pre-TableTools the dashboard stored hide
    // state in different keys per scope. Dual-write keeps existing renderers
    // (which read from DashState directly) in sync with TT writes and lets
    // users keep their currently-hidden items without a migration prompt.
    const LEGACY_KEY = {
        'vehicles':    NS + 'hiddenVehicles',
        'storages':    NS + 'hiddenStorages',
        'productions': NS + 'hiddenProductions',
        'sections':    NS + 'hiddenSections',
    };

    function readJSON(key, fallback) {
        try { const raw = localStorage.getItem(key); return raw == null ? fallback : JSON.parse(raw); }
        catch (_) { return fallback; }
    }
    function writeJSON(key, value) {
        try { localStorage.setItem(key, JSON.stringify(value)); } catch (_) {}
        // Mirror to server. ServerSync.syncWrite strips the NS prefix
        // internally so we can pass the full localStorage key directly.
        if (window.ServerSync) window.ServerSync.syncWrite(key, value);
    }
    function deleteKey(key) {
        try { localStorage.removeItem(key); } catch (_) {}
        if (window.ServerSync) window.ServerSync.syncDelete(key);
    }

    function getHidden(stateKey) {
        // Merge TT key + the legacy DashState key so the renderer sees a
        // single source of truth. Items only ever live in one set during
        // normal operation — the union just makes migration painless.
        const a = readJSON(KEY_HIDDEN(stateKey), []);
        const b = LEGACY_KEY[stateKey] ? readJSON(LEGACY_KEY[stateKey], []) : [];
        const out = new Set();
        for (const k of (Array.isArray(a) ? a : [])) out.add(String(k));
        for (const k of (Array.isArray(b) ? b : [])) out.add(String(k));
        return out;
    }
    function saveHidden(stateKey, set) {
        const arr = [...set];
        writeJSON(KEY_HIDDEN(stateKey), arr);
        if (LEGACY_KEY[stateKey]) writeJSON(LEGACY_KEY[stateKey], arr);
    }
    function getOrder(stateKey) {
        const arr = readJSON(KEY_ORDER(stateKey), null);
        return Array.isArray(arr) ? arr : null;
    }
    function saveOrder(stateKey, arr) { writeJSON(KEY_ORDER(stateKey), arr); }
    function clearOrder(stateKey)  { deleteKey(KEY_ORDER(stateKey)); }
    function clearHidden(stateKey) {
        deleteKey(KEY_HIDDEN(stateKey));
        if (LEGACY_KEY[stateKey]) deleteKey(LEGACY_KEY[stateKey]);
    }

    function hide(stateKey, itemKey) {
        const s = getHidden(stateKey); s.add(itemKey); saveHidden(stateKey, s);
    }
    function unhide(stateKey, itemKey) {
        const s = getHidden(stateKey); s.delete(itemKey); saveHidden(stateKey, s);
    }

    // Apply persisted custom order; new items (not in saved order) get appended.
    function applyOrder(items, stateKey, getKey) {
        const order = getOrder(stateKey);
        if (!order || !order.length) return items.slice();
        const byKey = new Map(items.map(i => [String(getKey(i)), i]));
        const seen = new Set();
        const out = [];
        for (const k of order) {
            const it = byKey.get(String(k));
            if (it) { out.push(it); seen.add(String(k)); }
        }
        for (const i of items) {
            const k = String(getKey(i));
            if (!seen.has(k)) out.push(i);
        }
        return out;
    }

    function split(items, stateKey, getKey) {
        const h = getHidden(stateKey);
        const visible = [], hidden = [];
        for (const i of items) {
            (h.has(String(getKey(i))) ? hidden : visible).push(i);
        }
        return { visible, hidden };
    }

    function escAttr(s) { return String(s).replace(/"/g, '&quot;'); }

    function hideBtn(stateKey, itemKey, label) {
        return `<button class="tt-hide" data-tt-hide="${escAttr(stateKey)}" data-tt-key="${escAttr(itemKey)}" title="${escAttr(label || 'Skrýt')}">✕</button>`;
    }
    function unhideBtn(stateKey, itemKey, label) {
        return `<button class="tt-hide" data-tt-show="${escAttr(stateKey)}" data-tt-key="${escAttr(itemKey)}" title="${escAttr(label || 'Zobrazit')}">+</button>`;
    }
    function dndAttrs(stateKey, itemKey) {
        // No `draggable="true"` — that would activate native HTML5 DnD on
        // top of Sortable's forceFallback pointer-event drag, causing the
        // two systems to fight over the same gesture.
        return `data-tt-dnd="${escAttr(stateKey)}" data-tt-key="${escAttr(itemKey)}"`;
    }
    // Compact row used as a header for the "Skryté (N)" subgroup inside a tbody.
    function hiddenSubgroupRow(stateKey, count, colspan) {
        return `<tr class="tt-hidden-sep" data-tt-hidden-toggle="${escAttr(stateKey)}"><td colspan="${colspan || 6}"><span class="group-toggle">▶</span> Skryté <span class="count">${count}</span></td></tr>`;
    }

    const renderCallbacks = {};
    // onChange wraps the consumer's renderer so that Sortable instances are
    // re-scanned after each re-render (the consumer typically rebuilds innerHTML,
    // which keeps the container element but may add new draggables in fresh
    // containers — those need their own Sortable instance).
    function onChange(stateKey, fn) {
        renderCallbacks[stateKey] = function () {
            const r = fn.apply(this, arguments);
            // Defer to the next frame so the render's DOM updates settle first.
            requestAnimationFrame(initSortableContainers);
            return r;
        };
    }
    function trigger(stateKey) { if (renderCallbacks[stateKey]) renderCallbacks[stateKey](); }

    // ─── Hide/unhide click delegation (unchanged) ────────────────────────────
    document.addEventListener('click', e => {
        const h = e.target.closest('button[data-tt-hide]');
        const s = e.target.closest('button[data-tt-show]');
        if (h) {
            e.stopPropagation();
            hide(h.dataset.ttHide, h.dataset.ttKey);
            trigger(h.dataset.ttHide);
            return;
        }
        if (s) {
            e.stopPropagation();
            unhide(s.dataset.ttShow, s.dataset.ttKey);
            trigger(s.dataset.ttShow);
            return;
        }
        // Toggle the "Skryté" subgroup visibility (rows below it until next .tt-hidden-sep or end)
        const sep = e.target.closest('[data-tt-hidden-toggle]');
        if (sep) {
            const tbody = sep.parentElement;
            const rows = [...tbody.children];
            const idx = rows.indexOf(sep);
            const toggle = sep.querySelector('.group-toggle');
            let collapsed;
            for (let i = idx + 1; i < rows.length; i++) {
                if (rows[i].classList.contains('tt-hidden-sep')) break;
                if (collapsed === undefined) collapsed = !rows[i].classList.contains('hidden-row');
                rows[i].classList.toggle('hidden-row', collapsed);
            }
            if (toggle) toggle.textContent = collapsed ? '▶' : '▼';
        }
    });

    // ─── Sortable.js init ────────────────────────────────────────────────────
    // Strategy: walk the DOM for all [data-tt-dnd] elements, group by their
    // parent container, attach a Sortable instance to each parent once. The
    // sortable instance is cached on the container DOM node (._tt_sortable)
    // so subsequent re-renders are no-ops.
    //
    // Cross-container scopes: any container in the same stateKey shares a
    // Sortable group (group: stateKey), so items dragged from a visible
    // container into one marked `data-tt-hidden` become hidden, and vice
    // versa. The hide set updates automatically — no ✕ buttons needed.
    function initSortableContainers() {
        if (typeof Sortable === 'undefined') return;
        const containers = new Map();   // container element → stateKey
        // Explicit containers (data-tt-container="scope") are always picked
        // up — even when empty — so an empty "Skryté" subgroup is still a
        // valid drop target.
        document.querySelectorAll('[data-tt-container]').forEach(el => {
            if (el._tt_sortable) return;
            containers.set(el, el.dataset.ttContainer);
        });
        // Implicit containers — parents of any [data-tt-dnd] item. This keeps
        // older scopes working without marker-attribute changes.
        document.querySelectorAll('[data-tt-dnd][data-tt-key]').forEach(el => {
            const container = el.parentElement;
            if (!container || container._tt_sortable) return;
            if (containers.has(container)) return;
            containers.set(container, el.dataset.ttDnd);
        });
        containers.forEach((stateKey, container) => {
            // Pick the drag target:
            //   1. .section-header (main dashboard + profit) — clicking and
            //      holding the entire section header starts the drag, which
            //      is what the user expects from a dashboard widget UX.
            //   2. .chart-header (history page) — same idea, different class.
            //   3. .drag-handle (Settings → Sekce panel rows) — short rows
            //      where the small ⠿ glyph is the natural handle.
            //   4. Nothing → whole row drag (table rows for vehicles, fields,
            //      animals, storages, etc.).
            const itemSel = `[data-tt-dnd="${cssEscape(stateKey)}"][data-tt-key]`;
            const handle =
                container.querySelector(`${itemSel} > .section-header`) ? '.section-header' :
                container.querySelector(`${itemSel} > .chart-header`)   ? '.chart-header'   :
                container.querySelector(`${itemSel} .drag-handle`)      ? '.drag-handle'    :
                null;
            const opts = {
                filter: 'input, button, a, .flash-toggle, .tt-hide, [data-no-drag]',
                preventOnFilter: false,
                // Only items matching this scope are draggable in this container.
                draggable: `[data-tt-dnd="${cssEscape(stateKey)}"][data-tt-key]`,
                // Group containers in the same scope so items can be dragged
                // between (e.g. main list ↔ "Skryté" subgroup). Cross-scope
                // drops (e.g. a section into the KPI row) are blocked in
                // `onMove` below — restricting via `put:` instead would have
                // left the rejected source orphaned on <body>, because
                // Sortable's snap-back is unreliable when forceFallback +
                // fallbackOnBody are both on.
                group: { name: stateKey, pull: true, put: true },
                animation: 180,
                easing: 'cubic-bezier(.2, .8, .2, 1)',
                ghostClass:  'tt-ghost',
                chosenClass: 'tt-chosen',
                dragClass:   'tt-dragging',
                // forceFallback uses Sortable's own drag implementation instead
                // of native HTML5 DnD — touch support, a consistent ghost across
                // browsers, and we can style it freely.
                forceFallback: true,
                fallbackOnBody: true,
                fallbackTolerance: 4,
                swapThreshold: 0.6,
                // Empty containers (e.g. the "Skryté …" zone before any item
                // is hidden) need a generous insert threshold or Sortable
                // refuses the drop unless the cursor lands within 5 px of
                // the container edge. 25 px makes drag-to-hide forgiving.
                emptyInsertThreshold: 25,
                // Long-press for touch so a casual tap doesn't start a drag
                // and page scrolling stays available. 500 ms is the de-facto
                // mobile standard (matches iOS context-menu timing). Desktop
                // drag is immediate because mouse intent is unambiguous.
                delay: 500,
                delayOnTouchOnly: true,
                touchStartThreshold: 6,
                onStart(evt) {
                    document.body.classList.add('tt-drag-active');
                    // Clear any text selection that was active before the drag
                    // — without this, the highlight from a previous click drag
                    // persists through the move and looks like a bug.
                    try { window.getSelection().removeAllRanges(); } catch (_) {}
                    // Remember origin so we can put the item back if Sortable
                    // leaves it stranded on <body>. With forceFallback +
                    // fallbackOnBody, a drag that ends over a rejecting
                    // container (or off-canvas) sometimes detaches the source.
                    evt.item._tt_origParent = evt.from;
                    evt.item._tt_origNext   = evt.item.nextElementSibling;
                    // Take over the floating clone's position so it tracks the
                    // cursor 1:1. Sortable's own forceFallback math is unreliable
                    // for items whose source has `position: absolute` (the
                    // masonry sections): we observed the fallback drifting only
                    // ~20 % of the cursor's actual motion. See attachFallbackTracking.
                    attachFallbackTracking();
                },
                // Prevent moving the source into a container of a different
                // scope. Returning false aborts the swap _before_ Sortable
                // touches the DOM, so a section can't drift into the KPI row
                // and a KPI card can't drift into the masonry. `evt.from`
                // and `evt.to` are the source/target containers; matching
                // their cached Sortable group names is the simplest reliable
                // scope check.
                onMove(evt) {
                    const fromKey = evt.from && evt.from._tt_sortable
                        && evt.from._tt_sortable.options.group.name;
                    const toKey = evt.to && evt.to._tt_sortable
                        && evt.to._tt_sortable.options.group.name;
                    if (fromKey && toKey && fromKey !== toKey) return false;
                    return true;
                },
                // Sortable fires onChange every time the dragged item swaps
                // with a sibling (i.e. its DOM index moves). With the masonry's
                // absolute positioning, the placeholder (`.tt-ghost`) wouldn't
                // visually move on its own — its inline top/left was set by
                // the last relayout. Re-pack the masonry on each swap so the
                // placeholder snaps to its new column slot and the user can
                // actually see where the section will land.
                onChange() {
                    if (stateKey === 'sections' && typeof window.relayoutMasonry === 'function') {
                        window.relayoutMasonry();
                    }
                },
                onEnd(evt) {
                    document.body.classList.remove('tt-drag-active');
                    detachFallbackTracking();
                    // Snap-back guard: if Sortable orphaned the item on <body>
                    // (forceFallback+fallbackOnBody + a rejected cross-scope
                    // drop has been observed to leave it there), restore it.
                    if (evt.item.parentElement === document.body
                            && evt.item._tt_origParent
                            && evt.item._tt_origParent.isConnected) {
                        evt.item._tt_origParent.insertBefore(evt.item, evt.item._tt_origNext);
                    }
                    delete evt.item._tt_origParent;
                    delete evt.item._tt_origNext;
                    onScopeChange(stateKey, evt);
                    // Re-pack the masonry once a section drag settles — the
                    // absolutely-positioned sections need new top/left after
                    // their DOM order changes. `onScopeChange → trigger →
                    // renderCallbacks` doesn't cover the `sections` scope (no
                    // renderer is registered for it), so call it explicitly.
                    if (stateKey === 'sections' && typeof window.relayoutMasonry === 'function') {
                        window.relayoutMasonry();
                    }
                },
            };
            if (handle) opts.handle = handle;
            container._tt_sortable = Sortable.create(container, opts);
        });
    }

    // Called from Sortable.onEnd: persist the new order (combining all
    // containers in the scope) and update the hidden set when an item moved
    // between visible and `data-tt-hidden` containers.
    function onScopeChange(stateKey, evt) {
        const itemSel = `[data-tt-dnd="${cssEscape(stateKey)}"][data-tt-key]`;
        const containers = [...document.querySelectorAll('[data-tt-container="' + cssEscape(stateKey) + '"]')];
        // Fallback when consumers don't mark containers explicitly: derive
        // them from the parents of every item in this scope.
        if (!containers.length) {
            const set = new Set();
            document.querySelectorAll(itemSel).forEach(el => { if (el.parentElement) set.add(el.parentElement); });
            containers.push(...set);
        }
        // Build the combined order. When a scope has MIRROR containers (the
        // dashboard masonry + the settings-panel section-list are both
        // `data-tt-dnd="sections"` views over the same data), naively
        // concatenating yields duplicated keys and applySectionOrder ends up
        // appending each section twice — leaving the DOM in the second
        // mirror's order (i.e. snapping back to the mirror's stale order).
        // Fix: source container (evt.from) is the user's actual intent;
        // start with its order, then append items from OTHER containers that
        // aren't already present (this preserves the drag-to-hide flow where
        // an item moves between visible and hidden containers).
        let combined;
        if (evt && evt.from && containers.includes(evt.from)) {
            const fromKeys = [...evt.from.children]
                .filter(el => el.matches(itemSel))
                .map(el => el.dataset.ttKey);
            const seen = new Set(fromKeys);
            const others = containers
                .filter(c => c !== evt.from)
                .flatMap(c => [...c.children].filter(el => el.matches(itemSel)))
                .map(el => el.dataset.ttKey)
                .filter(k => !seen.has(k) && seen.add(k));
            combined = [...fromKeys, ...others];
        } else {
            // No event (keyboard commit) — visible first, hidden last; dedupe
            // in case mirror containers contribute the same keys.
            const visible = containers.filter(c => !c.hasAttribute('data-tt-hidden'));
            const hidden  = containers.filter(c =>  c.hasAttribute('data-tt-hidden'));
            const all = [...visible, ...hidden]
                .flatMap(c => [...c.children].filter(el => el.matches(itemSel)))
                .map(el => el.dataset.ttKey);
            const seen = new Set();
            combined = all.filter(k => !seen.has(k) && seen.add(k));
        }
        saveOrder(stateKey, combined);

        // Cross-container drop: update the hidden set. evt.from / evt.to are
        // the actual source/target containers from Sortable.
        if (evt && evt.from !== evt.to && evt.item) {
            const key = evt.item.dataset.ttKey;
            const toHidden   = evt.to   && evt.to.hasAttribute('data-tt-hidden');
            const fromHidden = evt.from && evt.from.hasAttribute('data-tt-hidden');
            if (toHidden && !fromHidden)      hide(stateKey, key);
            else if (!toHidden && fromHidden) unhide(stateKey, key);
        }
        trigger(stateKey);
    }

    // ─── Fallback positioning override ────────────────────────────────────────
    // Sortable.js with forceFallback + fallbackOnBody is supposed to position
    // the floating clone (the element with `.tt-dragging`) so that the cursor
    // stays where the user originally clicked inside the source. In practice,
    // for items whose source has `position: absolute` (the masonry sections),
    // Sortable's translate values only move the clone a small fraction of the
    // cursor's actual delta — we measured a translate of (115, -154) when the
    // cursor had moved (590, -780). The user sees the floating chip stuck near
    // the source while the cursor drifts far away.
    //
    // Workaround: record the click offset on pointerdown, then on each rAF
    // tick during the drag, overwrite the floating clone's inline transform
    // so it lands at `(cursor - offset)`. This runs AFTER Sortable's own
    // pointermove handler, so our write wins.

    let _ttClickOffset = null;       // { x, y } — inside the source where pointer went down
    let _ttCursor      = { x: 0, y: 0 };  // last known viewport cursor
    let _ttRaf         = null;

    function recordCursor(e) {
        _ttCursor.x = e.clientX;
        _ttCursor.y = e.clientY;
    }

    // Capture phase so we see the event before any filter handler stops it.
    document.addEventListener('pointerdown', e => {
        const item = e.target && e.target.closest && e.target.closest('[data-tt-dnd][data-tt-key]');
        if (!item) { _ttClickOffset = null; return; }
        // Skip if the click landed on something the Sortable filter excludes —
        // those clicks never start a drag, so we'd be tracking phantom state.
        if (e.target.closest('input, button, a, .flash-toggle, .tt-hide, [data-no-drag]')) {
            _ttClickOffset = null;
            return;
        }
        const r = item.getBoundingClientRect();
        _ttClickOffset = { x: e.clientX - r.left, y: e.clientY - r.top };
        _ttCursor.x = e.clientX;
        _ttCursor.y = e.clientY;
    }, true);

    function attachFallbackTracking() {
        if (_ttRaf || !_ttClickOffset) return;
        document.addEventListener('pointermove', recordCursor, true);
        const tick = () => {
            const fb = document.body.querySelector(':scope > .tt-dragging');
            if (fb) {
                // Reset Sortable's own left/top to zero so the transform is the
                // only thing positioning the clone. Use important to outweigh
                // any stylesheet rule on .section / .chart-card / etc.
                fb.style.setProperty('position', 'fixed', 'important');
                fb.style.setProperty('left',     '0px',   'important');
                fb.style.setProperty('top',      '0px',   'important');
                fb.style.setProperty('margin',   '0',     'important');
                const x = _ttCursor.x - _ttClickOffset.x;
                const y = _ttCursor.y - _ttClickOffset.y;
                fb.style.setProperty('transform', `translate(${x}px, ${y}px)`, 'important');
            }
            _ttRaf = requestAnimationFrame(tick);
        };
        _ttRaf = requestAnimationFrame(tick);
    }

    function detachFallbackTracking() {
        if (_ttRaf) { cancelAnimationFrame(_ttRaf); _ttRaf = null; }
        document.removeEventListener('pointermove', recordCursor, true);
        _ttClickOffset = null;
    }

    // Tiny CSS.escape polyfill — used in the dynamic selector above so that
    // a stateKey containing weird characters can't break the query.
    function cssEscape(s) {
        if (typeof CSS !== 'undefined' && typeof CSS.escape === 'function') return CSS.escape(s);
        return String(s).replace(/[^a-zA-Z0-9_-]/g, ch => '\\' + ch);
    }

    // Initial pass on DOM ready, then keep watching for new draggables that
    // appear after the first render (e.g. WebSocket payload arrives 2 s later).
    function startObserving() {
        ensureAnnouncer();
        initSortableContainers();
        decorateHandlesA11y();
        decorateHiddenZones();
        const obs = new MutationObserver(() => {
            // Coalesce to one rAF tick so we don't thrash on every minor mutation.
            if (obs._pending) return;
            obs._pending = true;
            requestAnimationFrame(() => {
                obs._pending = false;
                initSortableContainers();
                decorateHandlesA11y();
                decorateHiddenZones();
            });
        });
        obs.observe(document.body, { childList: true, subtree: true });
    }

    // Hidden-zone collapse: inject the ▼ toggle into each .tt-hidden-zone
    // subgroup-header, restore the user's last collapsed state from
    // localStorage, and wire the click → toggle behaviour. Auto-runs on
    // every MutationObserver pass so re-rendered hidden zones don't lose
    // the toggle.
    function decorateHiddenZones() {
        document.querySelectorAll('.tt-hidden-zone').forEach(wrap => {
            if (wrap._tt_collapsible) return;
            wrap._tt_collapsible = true;
            const header = wrap.querySelector(':scope > .subgroup-header');
            if (!header) return;
            if (!header.querySelector('.group-toggle')) {
                const tog = document.createElement('span');
                tog.className = 'group-toggle';
                tog.textContent = '▼';
                tog.setAttribute('aria-hidden', 'true');
                header.insertBefore(tog, header.firstChild);
            }
            // Restore collapsed state from localStorage (keyed by wrap id).
            // Note: writeJSON below stores JSON.stringify('1') = '"1"' (with
            // quotes), so we must read it back through JSON.parse via
            // readJSON — a literal `=== '1'` comparison would never match
            // and the collapsed state would silently never restore.
            if (wrap.id) {
                if (readJSON(NS + 'collapsed:' + wrap.id, null) === '1') {
                    wrap.classList.add('collapsed');
                }
            }
        });
    }

    // Single delegated click handler — toggles the .collapsed class on the
    // parent .tt-hidden-zone and persists the new state. Runs once.
    document.addEventListener('click', e => {
        const header = e.target.closest('.tt-hidden-zone > .subgroup-header');
        if (!header) return;
        const wrap = header.parentElement;
        if (!wrap || !wrap.classList.contains('tt-hidden-zone')) return;
        const collapsed = wrap.classList.toggle('collapsed');
        if (wrap.id) {
            try {
                if (collapsed) writeJSON(NS + 'collapsed:' + wrap.id, '1');
                else           deleteKey(NS + 'collapsed:' + wrap.id);
            } catch (_) {}
        }
    });

    // ─── A11y: live announcer + keyboard reorder ─────────────────────────────
    // A single off-screen aria-live region announces position changes so
    // screen readers can follow keyboard reordering. The element is created
    // lazily on first need.
    function ensureAnnouncer() {
        if (document.getElementById('tt-announcer')) return;
        const div = document.createElement('div');
        div.id = 'tt-announcer';
        div.className = 'sr-only';
        div.setAttribute('aria-live', 'polite');
        div.setAttribute('aria-atomic', 'true');
        document.body.appendChild(div);
    }
    function announce(text) {
        const el = document.getElementById('tt-announcer');
        if (el) el.textContent = text;
    }

    // Make .drag-handle elements keyboard-focusable + give them an aria-label
    // that explains the keystrokes. Runs after each MutationObserver tick so
    // freshly rendered rows get the same treatment.
    function decorateHandlesA11y() {
        document.querySelectorAll('.drag-handle').forEach(h => {
            if (h._tt_a11y) return;
            h._tt_a11y = true;
            if (!h.hasAttribute('tabindex')) h.setAttribute('tabindex', '0');
            if (!h.getAttribute('role')) h.setAttribute('role', 'button');
            // Augment any existing aria-label with the keystroke instructions
            // so screen readers know the row is reorderable from the keyboard.
            const base = h.getAttribute('aria-label') || 'Přesunout';
            const kbHint = 'Stiskni mezerník pro aktivaci, šipky pro přesun, Enter pro potvrzení, Escape pro zrušení.';
            h.setAttribute('aria-label', base + '. ' + kbHint);
        });
    }

    // Keyboard reorder state. Activated by Space/Enter on a focused
    // .drag-handle inside a [data-tt-dnd][data-tt-key] item. Arrows move,
    // Enter/Space commits, Escape rolls back.
    let kbState = null;   // { item, container, stateKey, originalSibling }

    document.addEventListener('keydown', e => {
        const handle = e.target.closest('.drag-handle');
        if (!handle) return;
        const item = handle.closest('[data-tt-dnd][data-tt-key]');
        if (!item) return;
        const container = item.parentElement;
        const stateKey = item.dataset.ttDnd;

        // Begin or commit when active.
        if (e.key === ' ' || e.key === 'Enter') {
            e.preventDefault();
            if (!kbState) {
                kbState = {
                    item,
                    container,
                    stateKey,
                    // Save the original position so Escape can restore it.
                    originalSibling: item.nextSibling,
                };
                handle.classList.add('kb-moving');
                announce('Přesun aktivován. Šipky pro přesun, Enter pro potvrzení, Escape pro zrušení.');
            } else {
                commitKbMove();
            }
            return;
        }
        if (!kbState) return;

        if (e.key === 'Escape') {
            e.preventDefault();
            // Restore original DOM position.
            kbState.container.insertBefore(kbState.item, kbState.originalSibling);
            cancelKbMove('Přesun zrušen');
            return;
        }
        if (e.key === 'ArrowUp' || e.key === 'ArrowDown') {
            e.preventDefault();
            const dir = e.key === 'ArrowUp' ? -1 : 1;
            moveKb(dir);
        }
    });

    function moveKb(dir) {
        const { item, container, stateKey } = kbState;
        const sel = `[data-tt-dnd="${cssEscape(stateKey)}"][data-tt-key]`;
        const siblings = [...container.querySelectorAll(sel)].filter(el => el.parentElement === container);
        const idx = siblings.indexOf(item);
        const newIdx = idx + dir;
        if (newIdx < 0 || newIdx >= siblings.length) return;
        if (dir < 0) container.insertBefore(item, siblings[newIdx]);
        else         container.insertBefore(item, siblings[newIdx].nextSibling);
        announce(`Pozice ${newIdx + 1} z ${siblings.length}`);
        // Keep focus on the handle, which moved with the item.
        const h = item.querySelector('.drag-handle');
        if (h) h.focus();
    }

    function commitKbMove() {
        const { stateKey, item } = kbState;
        // Reuse the same persistence path Sortable uses: combine all
        // containers in the scope and write the order.
        onScopeChange(stateKey, null);
        const handle = item.querySelector('.drag-handle');
        if (handle) handle.classList.remove('kb-moving');
        announce('Pořadí uloženo.');
        kbState = null;
    }

    function cancelKbMove(msg) {
        const handle = kbState.item.querySelector('.drag-handle');
        if (handle) handle.classList.remove('kb-moving');
        announce(msg);
        kbState = null;
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', startObserving);
    } else {
        startObserving();
    }

    window.TableTools = {
        hide, unhide,
        applyOrder, split,
        getOrder, saveOrder, clearOrder,
        getHidden, clearHidden,
        hideBtn, unhideBtn, dndAttrs, hiddenSubgroupRow,
        onChange, trigger,
    };
})();
